from collections import Counter

@result_validator
def check_intersectional_bias(ctx: Dict[str, Any], result: Dict[str, Any]) -> Dict[str, Any]:
    decisions = ctx.get('batch_results', [])
    protected_attrs = ['gender', 'race', 'age_group']

    intersections = []
    for decision in decisions:
        key = tuple(decision.get(attr, 'unknown') for attr in protected_attrs)
        intersections.append((key, decision.get('approved', False)))

    counts = Counter(intersections)

    for (group, _), approved_count in counts.items():
        total = sum(c[1] for k, c in counts.items() if k[0] == group[0])
        group_approval = approved_count / total if total > 0 else 0

        if group_approval < 0.7:
            raise ValueError(f"Intersectional bias detected: {group} approval rate {group_approval:.1%}")

    return result

from pydantic_ai import StreamingAgent

class BiasStreamingValidator:
    def __init__(self):
        self.partial_protected = {}
        self.bias_thresholds = {'sentiment': 0.2, 'priority': 0.3}

    def validate_partial(self, chunk: Dict[str, Any]) -> bool:
        if 'language' in chunk and chunk['language'] == 'es':
            self.partial_protected.setdefault('es', []).append(chunk)

            if len(self.partial_protected['es']) > 5:
                priorities = [c.get('priority_score', 0) for c in self.partial_protected['es'][-5:]]
                if np.mean(priorities) < self.bias_thresholds['priority']:
                    raise ValueError("Language-based priority bias detected in stream")
        return True

streaming_agent = StreamingAgent(
    'support_model',
    validators=[BiasStreamingValidator()]
)

